// cli/internal/bead/backend.go
package bead

import "context"

// Backend is the storage contract for the bead tracker. Both the
// JSONL backend (cli/internal/bead/backend_jsonl.go) and the axon
// backend (cli/internal/bead/axon/) implement this surface. The
// chaos tests under cli/internal/bead/ run against any registered
// Backend via newTestStore(t, BackendName).
type Backend interface {
    // Init prepares storage (create JSONL file + lock dir; or for
    // axon: ensure collections exist and registered schema is current).
    Init(ctx context.Context) error

    // Get returns one bead with its OCC version. ErrNotFound for missing.
    Get(ctx context.Context, id string) (Bead, Version, error)

    // List returns all beads in the tracker collection (open + in_progress
    // + closed not yet archived). Order is unspecified.
    List(ctx context.Context) ([]Bead, error)

    // Create persists a new bead. Bead.ID may be empty; backend assigns
    // a ddx-<8hex> id and returns the assigned id. Fails if id is set
    // and already exists.
    Create(ctx context.Context, b Bead) (string, Version, error)

    // Update applies mutate to the bead identified by id under
    // optimistic concurrency control: read at version V, apply mutate,
    // write iff stored version == V. ErrVersionMismatch on conflict;
    // caller retries. Used by claim, status transitions, and any

package bead

import "io"

// RawBackend is the low-level storage contract — read/write the entire bead
// corpus and serialize concurrent rewrites. JSONLBackend and ExternalBackend
// implement it. Higher-level operations (CRUD, claim, ready/blocked, dep ops,
// events, archive, JSONL interchange) live on the Backend interface below and
// are composed on top of a RawBackend by Store.
type RawBackend interface {
	Init() error
	ReadAll() ([]Bead, error)
	WriteAll(beads []Bead) error
	WithLock(fn func() error) error
}

// Backend is the high-level bead-tracker contract that callers in
// cli/cmd/bead_*.go and the agent loop will eventually program against. It
// covers everything the bead description for ddx-bbdd7564 calls out: CRUD,
// claim, list/ready/blocked, dep ops, events append, archive split, and
// JSONL export/import.
//
// *Store satisfies this interface; the JSONL implementation lives in store.go
// and delegates per-write serialization to the configured RawBackend
// (JSONLBackend by default, ExternalBackend when DDX_BEAD_BACKEND or the
// .ddx/config.yaml beads.backend field selects bd/br).
//
// chaos_test.go and other conformance suites should program against this
// interface so additional backends can be exercised by the same tests.
type Backend interface {
	// Foundational
	Init() error
	ReadAll() ([]Bead, error)

	// CRUD
	Create(b *Bead) error
	Get(id string) (*Bead, error)
	Update(id string, mutate func(*Bead)) error
	Close(id string) error

	// Claim
	Claim(id, assignee string) error
	ClaimWithOptions(id, assignee, session, worktree string) error
	Unclaim(id string) error

	// Query
	List(status, label string, where map[string]string) ([]Bead, error)
	Ready() ([]Bead, error)
	Blocked() ([]Bead, error)

	// Dep ops
	DepAdd(id, depID string) error
	DepRemove(id, depID string) error
	DepTree(rootID string) (string, error)

	// Events
	AppendEvent(id string, event BeadEvent) error
	Events(id string) ([]BeadEvent, error)

	// Archive split
	Archive(policy ArchivePolicy) ([]string, error)
	Migrate() (MigrateStats, error)

	// JSONL interchange
	Import(source, filePath string) (int, error)
	ExportTo(w io.Writer) error
}

// BackendType constants
const (
	BackendJSONL = "jsonl"
	BackendBD    = "bd"
	BackendBR    = "br"
)

const DefaultCollection = "beads"

package bead

import (
	"encoding/json"
	"fmt"
	"time"
)

// Known field names that map to Bead struct fields (bd-compatible names).
var knownFields = map[string]bool{
	"id": true, "title": true, "issue_type": true, "status": true,
	"priority": true, "owner": true, "created_at": true, "created_by": true,
	"updated_at": true, "labels": true, "parent": true, "description": true,
	"acceptance": true, "dependencies": true, "notes": true,
	// Note: bd computed fields (dependency_count, dependent_count, comment_count)
	// are NOT in knownFields — they land in Extra and round-trip through it.
}

// unmarshalBead parses JSON into a Bead, preserving unknown fields in Extra.
func unmarshalBead(data []byte) (Bead, error) {
	var raw map[string]json.RawMessage
	if err := json.Unmarshal(data, &raw); err != nil {
		return Bead{}, fmt.Errorf("bead: unmarshal: %w", err)
	}

	var b Bead

	if v, ok := raw["id"]; ok {
		_ = json.Unmarshal(v, &b.ID)
	}
	if v, ok := raw["title"]; ok {
		_ = json.Unmarshal(v, &b.Title)
	}
	if v, ok := raw["issue_type"]; ok {
		_ = json.Unmarshal(v, &b.IssueType)
	}
	if v, ok := raw["status"]; ok {
		_ = json.Unmarshal(v, &b.Status)
	}
	if v, ok := raw["priority"]; ok {
		_ = json.Unmarshal(v, &b.Priority)
	}
	if v, ok := raw["owner"]; ok {
		_ = json.Unmarshal(v, &b.Owner)
	}
	if v, ok := raw["created_at"]; ok {
		var t time.Time
		if err := json.Unmarshal(v, &t); err == nil {
			b.CreatedAt = t
		}
	}
	if v, ok := raw["created_by"]; ok {
		_ = json.Unmarshal(v, &b.CreatedBy)
	}
	if v, ok := raw["updated_at"]; ok {
		var t time.Time
		if err := json.Unmarshal(v, &t); err == nil {
			b.UpdatedAt = t
		}
	}
	if v, ok := raw["labels"]; ok {
		_ = json.Unmarshal(v, &b.Labels)
	}
	if v, ok := raw["parent"]; ok {
		_ = json.Unmarshal(v, &b.Parent)
	}
	if v, ok := raw["description"]; ok {
		_ = json.Unmarshal(v, &b.Description)
	}
	if v, ok := raw["acceptance"]; ok {
		_ = json.Unmarshal(v, &b.Acceptance)
	}
	if v, ok := raw["notes"]; ok {
		_ = json.Unmarshal(v, &b.Notes)
	}
	if v, ok := raw["dependencies"]; ok {
		_ = json.Unmarshal(v, &b.Dependencies)
	}

	// Defaults
	if b.IssueType == "" {
		b.IssueType = DefaultType
	}
	if b.Status == "" {
		b.Status = DefaultStatus
	}

	// Collect unknown fields into Extra
	for k, v := range raw {
		if knownFields[k] {
			continue
		}
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		var val any
		_ = json.Unmarshal(v, &val)
		b.Extra[k] = val
	}

	return b, nil
}

// MarshalBead serializes a Bead to JSON, merging Extra fields back in.
// The output matches bd/br JSONL format.
func MarshalBead(b Bead) ([]byte, error) {
	return marshalBead(b)
}

func marshalBead(b Bead) ([]byte, error) {
	m := map[string]any{
		"id":         b.ID,
		"title":      b.Title,
		"status":     b.Status,
		"priority":   b.Priority,
		"issue_type": b.IssueType,
		"created_at": b.CreatedAt,
		"updated_at": b.UpdatedAt,
	}

	// Optional fields — only include if non-empty
	if b.Owner != "" {
		m["owner"] = b.Owner
	}
	if b.CreatedBy != "" {
		m["created_by"] = b.CreatedBy
	}
	if len(b.Labels) > 0 {
		m["labels"] = b.Labels
	}
	if b.Parent != "" {
		m["parent"] = b.Parent
	}
